int disc[N], low[N], timer = 0;
void dfs(int u, int p) {
    disc[u] = low[u] = ++timer;
    for (int v : adj[u]) {
        if (!disc[v]) { dfs(v, u); low[u] = min(low[u], low[v]); if (low[v] > disc[u]) bridges.push_back({u, v}); }
        else if (v != p) low[u] = min(low[u], disc[v]);
    }
}

