int LOG = ceil(log2(N));
vector<vector<int>> up(LOG + 1, vector<int>(N, 0));
// dfs: up[0][v] = par.
for (int k = 1; k <= LOG; k++) for (int v = 1; v <= N; v++) up[k][v] = up[k-1][up[k-1][v]];
int lca(int u, int v) {
    if (depth[u] < depth[v]) swap(u, v);
    int d = depth[u] - depth[v];
    for (int k = 0; k <= LOG; k++) if (d & (1 << k)) u = up[k][u];
    if (u == v) return u;
    for (int k = LOG; k >= 0; k--) if (up[k][u] != up[k][v]) { u = up[k][u]; v = up[k][v]; }
    return up[0][u];
}

long long diam = 0;
function<long long(int,int)> dfs = [&](int u, int p) -> long long {
    long long m1 = 0, m2 = 0;
    for (int v : adj[u]) if (v != p) {
        long long d = dfs(v, u) + 1;
        if (d > m1) { m2 = m1; m1 = d; } else if (d > m2) m2 = d;
    }
    diam = max(diam, m1 + m2);
    return m1;
};
