dp[1][0] = 0;
for (int mask = 1; mask < (1 << n); mask++)
    for (int u = 0; u < n; u++) if ((mask & (1 << u)) && dp[mask][u] != LLONG_MAX)
        for (int v = 0; v < n; v++) if (!(mask & (1 << v)))
            dp[mask | (1 << v)][v] = min(dp[mask | (1 << v)][v], dp[mask][u] + d[u][v]);

// F(X) = sum số trong [0, X] thoả; phân tích X thành chữ số d[].
function<long long(int,bool,int)> f = [&](int pos, bool tight, int sum) -> long long {
    if (pos == (int)d.size()) return /* check thoả */;
    if (!tight && memo[pos][sum] != -1) return memo[pos][sum];
    int limit = tight ? d[pos] : 9;
    long long res = 0;
    for (int x = 0; x <= limit; x++) res += f(pos + 1, tight && x == limit, sum + x);
    if (!tight) memo[pos][sum] = res;
    return res;
};

