struct Seg { vector<long long> t, lz; int n;
    void push(int v, int l, int r) { if (lz[v]) { t[v] += lz[v] * (r - l + 1); if (l != r) { lz[2*v] += lz[v]; lz[2*v+1] += lz[v]; } lz[v] = 0; } }
    void upd(int v, int l, int r, int ql, int qr, long long x) { push(v, l, r); if (qr < l || r < ql) return; if (ql <= l && r <= qr) { lz[v] += x; push(v, l, r); return; } int m = (l + r) / 2; upd(2*v, l, m, ql, qr, x); upd(2*v+1, m+1, r, ql, qr, x); t[v] = t[2*v] + t[2*v+1]; }
};

long long bit[N+1][M+1];
void upd(int i, int j, long long v) { for (int x = i; x <= N; x += x & -x) for (int y = j; y <= M; y += y & -y) bit[x][y] += v; }
long long qry(int i, int j) { long long s = 0; for (int x = i; x > 0; x -= x & -x) for (int y = j; y > 0; y -= y & -y) s += bit[x][y]; return s; }
